public void testEmptyValueSuppression() throws Exception
{
    ObjectMapper mapper = new ObjectMapper();
    mapper.enable(SerializationFeature.WRITE_EMPTY_JSON_ARRAYS);
    mapper.addMixIn(TwoStringsBean.class, EmptySuppressionMixin.class);
    String json = mapper.writeValueAsString(new TwoStringsBean("", "bar"));
    assertTrue("Empty string should be handled as placeholder or suppressed in column format", 
               json.contains("bar"));
}

@JsonFormat(shape = JsonFormat.Shape.ARRAY)
@JsonPropertyOrder({"first", "second"})
abstract class EmptySuppressionMixin {
    @JsonInclude(JsonInclude.Include.NON_EMPTY)
    abstract String getFirst();
}

public void testCustomNullSerializer() throws Exception
{
    ObjectMapper mapper = new ObjectMapper();
    SimpleModule module = new SimpleModule();
    module.addSerializer(String.class, new JsonSerializer<String>() {
        @Override
        public void serialize(String value, JsonGenerator gen, SerializerProvider serializers) throws IOException {
            if (value == null) {
                gen.writeString("CUSTOM_NULL");
            } else {
                gen.writeString(value);
            }
        }
    });
    mapper.registerModule(module);
    String json = mapper.writeValueAsString(new TwoStringsBean());
    assertTrue("Custom null serializer should be invoked", json.contains("null") || json.contains("CUSTOM_NULL"));
}

public void testDefaultValueSuppression() throws Exception
{
    ObjectMapper mapper = new ObjectMapper();
    mapper.setDefaultPropertyInclusion(JsonInclude.Value.construct(JsonInclude.Include.NON_DEFAULT, JsonInclude.Include.ALWAYS));
    String json = mapper.writeValueAsString(new TwoStringsBean("default", "bar"));
    assertTrue("Should serialize with default value handling", json.contains("bar"));
}
